// Защита: разрешаем ТОЛЬКО SELECT, без точек с запятой (одно выражение).
const raw = ($json.query || '').toString().trim();
if (!raw) throw new Error('query is required');
if (raw.length > 4000) throw new Error('query too long');

// Удаляем trailing semicolon если он один.
const q = raw.replace(/;\s*$/, '');

// Запрещаем доп. statement-ы.
if (/;/.test(q)) throw new Error('multiple statements are not allowed');

// Запрещаем небезопасные ключевые слова в начале/как самостоятельные слова.
const forbidden = /\b(insert|update|delete|drop|alter|create|truncate|grant|revoke|copy|do|call|set\s+role|reset)\b/i;
if (forbidden.test(q)) throw new Error('only read-only SELECT/WITH queries are allowed');

// Должно начинаться на SELECT или WITH (CTE).
if (!/^(select|with)\b/i.test(q)) throw new Error('query must start with SELECT or WITH');

// Принудительный LIMIT, если его нет (защита от случайного полного скана).
let finalQuery = q;
if (!/\blimit\s+\d+/i.test(q)) finalQuery = `${q}\nLIMIT 200`;

return [{ json: { safeQuery: finalQuery } }];

// Сводим строки в массив объектов и обрезаем до 200.
const rows = $input.all().map(i => i.json).slice(0, 200);
return [{ json: { rows, count: rows.length } }];
